 */
exports.main = function (config, context) {

    // ── LMC-Variablen ─────────────────────────────────────────────────────────
    var snmpUser = context.vars.SNMP_USER || 'snmpclient';
    var authPassword = context.vars.SNMP_AUTH_PW || 'REDACTED';
    var privPassword = context.vars.SNMP_PRIV_PW || 'REDACTED';
    var authProto = context.vars.SNMP_AUTH_PROTO || 'HMAC-SHA';
    var privProto = context.vars.SNMP_PRIV_PROTO || 'AES';
    var viewName = 'readAll';
    var groupName = 'readGroup';

    // ------------------------------------------------------------------------
    // Meldungen/Monitoring/Protokolle/SNMP/SNMP-Einstellungen/Zugangskonfiguration/Benutzer
    // ------------------------------------------------------------------------
    var table = config.getTableByOid("1.2.9.32");
    var row;

    row = table.createNewRow();
    row.setByOid("13", "1"); // Eintrag aktiv
    row.setByOid("2", "snmpclient"); // Benutzername
    row.setByOid("5", "3"); // Authentifizierung
    row.setByOid("6", "REDACTED"); // Password für Auth.
    row.setByOid("14", ""); // Hauptgerätepasswort
    row.setByOid("8", "4"); // Verschlüsselung
    row.setByOid("9", "REDACTED"); // Password für Verschl.
    row.setByOid("15", ""); // Hauptgerätepasswort
    table.addOrMerge(row);

    // ------------------------------------------------------------------------
    // Meldungen/Monitoring/Protokolle/SNMP/SNMP-Einstellungen/Zugangskonfiguration/Gruppen
    // ------------------------------------------------------------------------
    var table = config.getTableByOid("1.2.9.28");
    var row;
    row = table.createNewRow();
    row.setByOid("5", "1"); // Eintrag aktiv
    row.setByOid("3", "snmpv3group"); // Gruppenname
    row.setByOid("2", "snmpclient"); // Benutzer/Security-Name
    row.setByOid("1", "3"); // Security-Model
    table.addOrMerge(row);

    // ------------------------------------------------------------------------
    // Meldungen/Monitoring/Protokolle/SNMP/SNMP-Einstellungen/Zugangskonfiguration/Zugriffsrechte
    // ------------------------------------------------------------------------
    var table = config.getTableByOid("1.2.9.29");
    var row;
    row = table.createNewRow();
    row.setByOid("9", "1"); // Eintrag aktiv
    row.setByOid("1", "snmpv3group"); // Gruppenname
    row.setByOid("5", "Full-Access"); // Ansicht mit Leserechten
    row.setByOid("7", "Full-Access"); // Ansicht mit Leser.(Traps)
    row.setByOid("6", "Full-Access"); // Ansicht mit Schreibrechten
    row.setByOid("3", "3"); // Security-Model
    row.setByOid("10", "3"); // Minimale Sicherheit
    table.addOrMerge(row);

};
